mapper.insert:
/*ReplaceUsimMapper.saveFreeUsimReqMst*/

  SELECT SQ_FREE_USIM_REQ_MST.NEXTVAL FROM DUAL

INSERT INTO NMCP_FREE_USIM_REQ_MST (
   SEQ
  ,CUSTOMER_ID
  ,CHNL_CD
  ,REQ_QNTY
  ,DLVRY_NAME
  ,DLVRY_TEL_FN
  ,DLVRY_TEL_MN
  ,DLVRY_TEL_RN
  ,DLVRY_POST
  ,DLVRY_ADDR
  ,DLVRY_ADDR_DTL
  ,DLVRY_MEMO
  ,AGRM_YN
  ,ONLINE_AUTH_INFO
  ,STATUS
  ,REQ_IN_DAY
  ,CRET_ID
  ,CRET_DTTM
  ,OSST_NO
) VALUES (
   #{seq}
  ,#{customerId}
  ,'ON'
  ,#{reqQnty}
  ,#{dlvryName}
  ,#{dlvryTelFn}
  ,#{dlvryTelMn}
  ,#{dlvryTelRn}
  ,#{dlvryPost}
  ,#{dlvryAddr}
  ,#{dlvryAddrDtl}
  ,#{dlvryMemo}
  ,#{agrmYn}
  ,#{onlineAuthInfo}
  ,'REQ'
  ,SYSDATE
  ,#{cretId}
  ,SYSDATE
  ,#{osstNo}
)

/*ReplaceUsimMapper.saveFreeUsimReqDtl*/
INSERT INTO NMCP_FREE_USIM_REQ_DTL (
   SEQ
  ,SUB_SEQ
  ,CONTRACT_NUM
  ,STATUS
  ,CRET_ID
  ,CRET_DTTM
  ,PRE_CHK_RSLT_CD
  ,PRE_CHK_RSLT_MSG
  ,NFC_USIM_YN
  ,USIM_MODEL_CD
  ,USIM_MODEL_ID
) VALUES (
   #{seq}
  ,(SELECT COUNT(SEQ) + 1 FROM NMCP_FREE_USIM_REQ_DTL WHERE SEQ = #{seq})
  ,#{contractNum}
  ,'REQ'
  ,#{cretId}
  ,SYSDATE
  ,'00'
  ,'처리성공'
  ,#{nfcUsimYn}
  ,#{usimModelCd}
  ,#{usimModelId}
)
